      field = "x",
      module = 1:10
    ),
    "argument must be a reference class"
  )

  #' @description Test that `set_param_vector()` requires the `module_input` argument to be a tibble.
  expect_error(
    set_param_vector(
      field = "x",
      module = methods::new(EWAAGrowth),
      module_input = 1:10
    ),
    "argument must be a tibble"
  )
  clear()
})
